from flask import Flask, request, jsonify
import jwt
import requests
import os

app = Flask(__name__)

BACKEND_URL = os.getenv("BACKEND_URL", "http://localhost:5001")

HOP_BY_HOP_HEADERS = {
    "connection",
    "keep-alive",
    "proxy-authenticate",
    "proxy-authorization",
    "te",
    "trailers",
    "transfer-encoding",
    "upgrade",
    "host",
    "content-length",
}


def get_bearer_token():
    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        return None
    return auth_header.split(" ", 1)[1].strip()


def decode_and_validate_jwt(token):
    unverified_header = jwt.get_unverified_header(token)
    alg = unverified_header.get("alg")
    if not alg or alg.lower() == "none":
        raise jwt.InvalidAlgorithmError("Invalid token algorithm")

    claims = jwt.decode(
        token,
        options={
            "verify_signature": False,
            "verify_exp": True,
            "verify_nbf": True,
            "verify_iat": True,
            "verify_aud": False,
            "verify_iss": False,
            "require": ["exp"],
        },
        algorithms=[alg],
    )
    return claims


def build_forward_headers(claims):
    headers = {}
    for key, value in request.headers.items():
        if key.lower() not in HOP_BY_HOP_HEADERS:
            headers[key] = value

    if "sub" in claims:
        headers["X-User-Sub"] = str(claims["sub"])
    if "email" in claims:
        headers["X-User-Email"] = str(claims["email"])
    if "roles" in claims:
        roles = claims["roles"]
        if isinstance(roles, (list, tuple)):
            headers["X-User-Roles"] = ",".join(map(str, roles))
        else:
            headers["X-User-Roles"] = str(roles)
    headers["X-User-Claims"] = jwt.encode(claims, key="", algorithm="HS256")
    return headers


@app.route("/", defaults={"path": ""}, methods=["GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS"])
@app.route("/<path:path>", methods=["GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS"])
def gateway(path):
    token = get_bearer_token()
    if not token:
        return jsonify({"error": "Missing or invalid Authorization header"}), 401

    try:
        claims = decode_and_validate_jwt(token)
    except jwt.ExpiredSignatureError:
        return jsonify({"error": "Token expired"}), 401
    except jwt.InvalidTokenError as e:
        return jsonify({"error": f"Invalid token: {str(e)}"}), 401

    forward_headers = build_forward_headers(claims)
    target_url = f"{BACKEND_URL.rstrip('/')}/{path}"

    try:
        resp = requests.request(
            method=request.method,
            url=target_url,
            params=request.args,
            headers=forward_headers,
            data=request.get_data(),
            cookies=request.cookies,
            allow_redirects=False,
            timeout=30,
        )
    except requests.RequestException as e:
        return jsonify({"error": "Backend request failed", "details": str(e)}), 502

    response_headers = [
        (name, value)
        for name, value in resp.headers.items()
        if name.lower() not in HOP_BY_HOP_HEADERS
    ]

    return resp.content, resp.status_code, response_headers


